// ---- Accessibility in Android ----

// ---- Accessible Compose Components ----

// ---- Basic accessibility ----
@Composable
fun AccessibleButton() {
    Button(
        onClick = { /* action */ },
        modifier = Modifier
            .semantics {
                role = Role.Button
                contentDescription = "Submit form"
            }
    ) {
        Text("Submit")
    }
}

// ---- Accessibility with label ----
@Composable
fun AccessibleTextField() {
    var text by remember { mutableStateOf("") }

    TextField(
        value = text,
        onValueChange = { text = it },
        label = { Text("Enter your name") },
        modifier = Modifier
            .semantics {
                stateDescription = if (text.isEmpty()) "Empty" else text
            }
    )
}

// ---- Custom accessibility ----
@Composable
fun AccessibleCard() {
    Card(
        modifier = Modifier
            .clickable { /* action */ }
            .semantics {
                role = Role.Button
                contentDescription = "Item 1"
                stateDescription = "Selected"
            }
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text("Item Title")
            Text("Item Description")
        }
    }
}

// ---- Accessibility with TalkBack ----
@Composable
fun TalkBackScreen() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
            .semantics {
                contentDescription = "Main screen with items"
            }
    ) {
        Text(
            text = "Welcome",
            modifier = Modifier.semantics {
                heading()
            }
        )

        ItemList()
    }
}

// ---- Accessibility for custom views ----
@Composable
fun CustomAccessibleView() {
    var isChecked by remember { mutableStateOf(false) }

    Row(
        modifier = Modifier
            .clickable { isChecked = !isChecked }
            .semantics {
                role = Role.Checkbox
                contentDescription = "Enable notifications"
                stateDescription = if (isChecked) "On" else "Off"
                toggleableState = if (isChecked) ToggleableState.On else ToggleableState.Off
                onPress = { isChecked = !isChecked }
            }
    ) {
        Text("Enable notifications")
        if (isChecked) {
            Icon(Icons.Default.Check, null)
        }
    }
}

// ---- Accessibility for animations ----
@Composable
fun AccessibleAnimation() {
    val animatedValue by animateFloatAsState(
        targetValue = 1f,
        animationSpec = tween(1000)
    )

    Box(
        modifier = Modifier
            .size(100.dp)
            .graphicsLayer {
                alpha = animatedValue
            }
            .semantics {
                // Disable accessibility for decorative animations
                importantForAccessibility = ImportantForAccessibility.No
            }
    )
}

// ---- Accessibility with live region ----
@Composable
fun LiveRegionExample() {
    var message by remember { mutableStateOf("") }

    Column {
        Button(
            onClick = { message = "Loading..." }
        ) {
            Text("Load Data")
        }

        Text(
            text = message,
            modifier = Modifier.semantics {
                liveRegion = LiveRegionMode.Assertive
            }
        )
    }
}

// ---- Accessibility service ----
class AccessibilityService : AccessibilityService() {
    override fun onAccessibilityEvent(event: AccessibilityEvent) {
        // Handle accessibility events
    }

    override fun onInterrupt() {
        // Handle interruption
    }
}

// ---- Accessibility test ----
@OptIn(ExperimentalTestApi::class)
class AccessibilityTest {
    @get:Rule
    val composeTestRule = createComposeRule()

    @Test
    fun testAccessibility() {
        composeTestRule.setContent {
            AccessibleButton()
        }

        composeTestRule.onNodeWithContentDescription("Submit form")
            .assertExists()
            .assertHasClickAction()
    }

    @Test
    fun testAccessibilityLabels() {
        composeTestRule.setContent {
            AccessibleTextField()
        }

        composeTestRule.onNodeWithText("Enter your name")
            .assertExists()
    }
}

